class APMDataSanitizer:
    """Sanitizes APM data to prevent exposure of sensitive information."""

    # Patterns for sensitive data detection
    SENSITIVE_FIELD_PATTERNS = [
        re.compile(r'(?i)(password|passwd|pwd|secret)'),
        re.compile(r'(?i)(token|api[_-]?key|apikey|access[_-]?key)'),
        re.compile(r'(?i)(authorization|auth[_-]?token|bearer)'),
        re.compile(r'(?i)(credit[_-]?card|card[_-]?number|cvv|cvc)'),
        re.compile(r'(?i)(ssn|social[_-]?security)'),
        re.compile(r'(?i)(private[_-]?key|encryption[_-]?key)'),
        re.compile(r'(?i)(session[_-]?id|session[_-]?token|csrf)'),
        re.compile(r'(?i)(cookie|set[_-]?cookie)'),
        re.compile(r'(?i)(bank[_-]?account|routing[_-]?number)'),
        re.compile(r'(?i)(pin|security[_-]?code|security[_-]?answer)'),
    ]

    SENSITIVE_VALUE_PATTERNS = [
        # Credit card numbers (basic pattern)
        re.compile(r'\b\d{4}[- ]?\d{4}[- ]?\d{4}[- ]?\d{4}\b'),
        # SSN
        re.compile(r'\b\d{3}-\d{2}-\d{4}\b'),
        # Email addresses
        re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'),
        # Bearer tokens
        re.compile(r'Bearer\s+[A-Za-z0-9\-._~+/]+=*'),
        # JWT tokens
        re.compile(r'eyJ[A-Za-z0-9\-_]+\.eyJ[A-Za-z0-9\-_]+\.[A-Za-z0-9\-_]+'),
        # AWS keys
        re.compile(r'AKIA[0-9A-Z]{16}'),
    ]

    REDACTED = '[REDACTED]'

    # SQL patterns that might contain sensitive data
    SQL_SENSITIVE_PATTERNS = [
        re.compile(r"(?i)(INSERT\s+INTO\s+\w+\s*\([^)]*(?:password|token|secret|key)[^)]*\)\s*VALUES\s*\()([^)]+)(\))"),
        re.compile(r"(?i)(WHERE\s+(?:password|token|secret|api_key)\s*=\s*)'[^']*'"),
        re.compile(r"(?i)(SET\s+(?:password|token|secret|api_key)\s*=\s*)'[^']*'"),
    ]

    @classmethod
    def is_sensitive_field(cls, field_name: str) -> bool:
        """Check if a field name indicates sensitive data."""
        if not isinstance(field_name, str):
            return False
        return any(pattern.search(field_name) for pattern in cls.SENSITIVE_FIELD_PATTERNS)

    @classmethod
    def contains_sensitive_value(cls, value: str) -> bool:
        """Check if a value contains sensitive data patterns."""
        if not isinstance(value, str):
            return False
        return any(pattern.search(value) for pattern in cls.SENSITIVE_VALUE_PATTERNS)

    @classmethod
    def sanitize_dict(cls, data: Dict[str, Any], depth: int = 0) -> Dict[str, Any]:
        """Recursively sanitize a dictionary, redacting sensitive fields."""
        if depth > 10:  # Prevent infinite recursion
            return {cls.REDACTED: cls.REDACTED}

        sanitized = {}
        for key, value in data.items():
            if cls.is_sensitive_field(str(key)):
                sanitized[key] = cls.REDACTED
            elif isinstance(value, dict):
                sanitized[key] = cls.sanitize_dict(value, depth + 1)
            elif isinstance(value, list):
                sanitized[key] = cls.sanitize_list(value, depth + 1)
            elif isinstance(value, str):
                sanitized[key] = cls.sanitize_string(value)
            else:
                sanitized[key] = value
        return sanitized

    @classmethod
    def sanitize_list(cls, data: List[Any], depth: int = 0) -> List[Any]:
        """Sanitize a list of values."""
        if depth > 10:
            return [cls.REDACTED]

        sanitized = []
        for item in data:
            if isinstance(item, dict):
                sanitized.append(cls.sanitize_dict(item, depth + 1))
            elif isinstance(item, list):
                sanitized.append(cls.sanitize_list(item, depth + 1))
            elif isinstance(item, str):
                sanitized.append(cls.sanitize_string(item))
            else:
                sanitized.append(item)
        return sanitized

    @classmethod
    def sanitize_string(cls, value: str) -> str:
        """Sanitize a string value, redacting sensitive patterns."""
        if cls.contains_sensitive_value(value):
            return cls.REDACTED
        return value

    @classmethod
    def sanitize_sql(cls, sql: str) -> str:
        """Sanitize SQL queries to remove sensitive data from values."""
        if not isinstance(sql, str):
            return str(sql)

        sanitized = sql
        # Replace string literals in sensitive contexts
        for pattern in cls.SQL_SENSITIVE_PATTERNS:
            sanitized = pattern.sub(lambda m: m.group(1) + cls.REDACTED, sanitized)

        # General: replace all string literal values with placeholders for safety
        # This preserves query structure but removes actual values
        sanitized = re.sub(r"'[^']*'", "'?'", sanitized)
        return sanitized

    @classmethod
    def sanitize_headers(cls, headers: Dict[str, str]) -> Dict[str, str]:
        """Sanitize HTTP headers."""
        sensitive_headers = {
            'authorization', 'cookie', 'set-cookie', 'x-api-key',
            'x-auth-token', 'proxy-authorization', 'x-csrf-token',
            'x-forwarded-for',  # PII - IP addresses
        }
        sanitized = {}
        for key, value in headers.items():
            if key.lower() in sensitive_headers or cls.is_sensitive_field(key):
                sanitized[key] = cls.REDACTED
            else:
                sanitized[key] = cls.sanitize_string(str(value))
        return sanitized

    @classmethod
    def sanitize_url(cls, url: str) -> str:
        """Sanitize URL query parameters that might contain sensitive data."""
        if not isinstance(url, str):
            return str(url)

        # Remove sensitive query parameters
        import urllib.parse
        parsed = urllib.parse.urlparse(url)
        if parsed.query:
            params = urllib.parse.parse_qs(parsed.query)
            sanitized_params = {}
            for key, values in params.items():
                if cls.is_sensitive_field(key):
                    sanitized_params[key] = [cls.REDACTED]
                else:
                    sanitized_params[key] = [
                        cls.sanitize_string(v) for v in values
                    ]
            sanitized_query = urllib.parse.urlencode(sanitized_params, doseq=True)
            parsed = parsed._replace(query=sanitized_query)
        return urllib.parse.urlunparse(parsed)

    @classmethod
    def sanitize_stack_trace(cls, stack_trace: str) -> str:
        """Sanitize stack traces to remove sensitive file paths and data."""
        if not isinstance(stack_trace, str):
            return str(stack_trace)

        # Remove absolute file paths (keep relative)
        sanitized = re.sub(
            r'File "(/[^"]*/)([^/"]+)"',
            r'File "\2"',
            stack_trace
        )
        # Remove any embedded sensitive values in stack traces
        for pattern in cls.SENSITIVE_VALUE_PATTERNS:
            sanitized = pattern.sub(cls.REDACTED, sanitized)

        return sanitized


