class APMSpan:
    """Represents a span (unit of work) within a transaction."""

    def __init__(self, name: str, span_type: str, parent_id: Optional[str] = None):
        self.span_id = hashlib.md5(
            f"{name}{time.time_ns()}".encode()
        ).hexdigest()[:16]
        self.name = name
        self.span_type = span_type
        self.parent_id = parent_id
        self.start_time = None
        self.end_time = None
        self.duration_ms = 0
        self.context: Dict[str, Any] = {}
        self.labels: Dict[str, Any] = {}
        self.outcome = 'unknown'
        self.stack_trace: Optional[str] = None

    def start(self):
        self.start_time = time.monotonic()
        return self

    def end(self, outcome: str = 'success'):
        self.end_time = time.monotonic()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        self.outcome = outcome

    def set_context(self, context: Dict[str, Any]):
        """Set span context with sanitization."""
        self.context = APMDataSanitizer.sanitize_dict(context)

    def set_label(self, key: str, value: Any):
        if APMDataSanitizer.is_sensitive_field(key):
            logger.warning(f"Attempted to set sensitive label '{key}' - blocked")
            return
        if isinstance(value, str):
            value = APMDataSanitizer.sanitize_string(value)
        self.labels[key] = value

    def to_dict(self) -> Dict[str, Any]:
        result = {
            'span_id': self.span_id,
            'name': self.name,
            'type': self.span_type,
            'parent_id': self.parent_id,
            'duration_ms': round(self.duration_ms, 2),
            'outcome': self.outcome,
            'context': self.context,
            'labels': self.labels,
        }
        if self.stack_trace:
            result['stack_trace'] = APMDataSanitizer.sanitize_stack_trace(
                self.stack_trace
            )
        return result


class APMTransaction:
    """Represents a transaction (top-level unit of work)."""

    def __init__(self, name: str, transaction_type: str = 'request'):
        self.transaction_id = hashlib.md5(
            f"{name}{time.time_ns()}".encode()
        ).hexdigest()[:16]
        self.name = name
        self.transaction_type = transaction_type
        self.start_time = None
        self.end_time = None
        self.duration_ms = 0
        self.result: Optional[str] = None
        self.outcome = 'unknown'
        self.context: Dict[str, Any] = {}
        self.labels: Dict[str, Any] = {}
        self.spans: List[APMSpan] = []
        self.custom_context: Dict[str, Any] = {}

    def start(self):
        self.start_time = time.monotonic()
        logger.info(f"Transaction started: {self.name} [{self.transaction_id}]")
        return self

    def end(self, result: str = 'success', outcome: str = 'success'):
        self.end_time = time.monotonic()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        self.result = result
        self.outcome = outcome
        logger.info(
            f"Transaction ended: {self.name} [{self.transaction_id}] "
            f"duration={self.duration_ms:.2f}ms outcome={outcome}"
        )

    def set_context(self, context: Dict[str, Any]):
        self.context = APMDataSanitizer.sanitize_dict(context)

    def set_custom_context(self, context: Dict[str, Any]):
        self.custom_context = APMDataSanitizer.sanitize_dict(context)

    def set_label(self, key: str, value: Any):
        if APMDataSanitizer.is_sensitive_field(key):
            logger.warning(f"Attempted to set sensitive label '{key}' - blocked")
            return
        if isinstance(value, str):
            value = APMDataSanitizer.sanitize_string(value)
        self.labels[key] = value

    def create_span(self, name: str, span_type: str) -> APMSpan:
        span = APMSpan(name, span_type, parent_id=self.transaction_id)
        self.spans.append(span)
        return span

    def to_dict(self) -> Dict[str, Any]:
        return {
            'transaction_id': self.transaction_id,
            'name': self.name,
            'type': self.transaction_type,
            'duration_ms': round(self.duration_ms, 2),
            'result': self.result,
            'outcome': self.outcome,
            'context': self.context,
            'custom_context': self.custom_context,
            'labels': self.labels,
            'spans': [span.to_dict() for span in self.spans],
            'span_count': len(self.spans),
        }


