class APMClient:
    """
    Application Performance Monitoring client.
    Captures transactions, spans, errors, and SQL queries with full sanitization.
    """

    def __init__(self, config: Optional[Dict[str, Any]] = None):
        self.config = self._build_config(config or {})
        self._transactions: List[Dict[str, Any]] = []
        self._errors: List[Dict[str, Any]] = []
        self._current_transaction: Optional[APMTransaction] = None
        self._is_recording = True
        self._sanitizer = APMDataSanitizer()

        logger.info(
            f"APM Client initialized for service: {self.config['service_name']} "
            f"environment: {self.config['environment']}"
        )

    def _build_config(self, user_config: Dict[str, Any]) -> Dict[str, Any]:
        """Build configuration with secure defaults."""
        config = {
            'service_name': os.environ.get('APM_SERVICE_NAME', 'my-application'),
            'environment': os.environ.get('APM_ENVIRONMENT', 'development'),
            'server_url': os.environ.get('APM_SERVER_URL', 'http://localhost:8200'),
            # Secret token should come from environment, never hardcoded
            'secret_token': os.environ.get('APM_SECRET_TOKEN', ''),
            # Performance settings
            'transaction_sample_rate': float(
                os.environ.get('APM_SAMPLE_RATE', '1.0')
            ),
            'capture_body': os.environ.get('APM_CAPTURE_BODY', 'all'),
            'capture_headers': True,
            'collect_sql_queries': True,
            'stack_trace_limit': 50,
            # Security settings - sanitization
            'sanitize_field_names': [
                'password', 'passwd', 'pwd', 'secret', 'token',
                'api_key', 'apikey', 'access_key', 'authorization',
                'credit_card', 'card_number', 'cvv', 'ssn',
                'private_key', 'session_id', 'cookie',
            ],
            # Transport security
            'verify_server_cert': True,
            'server_timeout': 30,
            # Data retention
            'max_transactions_buffer': 1000,
            'max_errors_buffer': 100,
        }
        # Override with user config (but never expose secret_token in logs)
        for key, value in user_config.items():
            if key != 'secret_token':
                config[key] = value
            else:
                config[key] = value  # Set but don't log

        return config

    def begin_transaction(
        self, name: str, transaction_type: str = 'request'
    ) -> APMTransaction:
        """Begin a new transaction."""
        transaction = APMTransaction(name, transaction_type)
        transaction.start()
        self._current_transaction = transaction
        return transaction

    def end_transaction(
        self, result: str = 'success', outcome: str = 'success'
    ):
        """End the current transaction and store it."""
        if self._current_transaction:
            self._current_transaction.end(result, outcome)
            self._store_transaction(self._current_transaction)
            self._current_transaction = None

    def _store_transaction(self, transaction: APMTransaction):
        """Store transaction data with sanitization."""
        data = transaction.to_dict()
        # Final sanitization pass
        data = self._sanitizer.sanitize_dict(data)

        if len(self._transactions) >= self.config['max_transactions_buffer']:
            self._flush_transactions()

        self._transactions.append(data)
        logger.debug(f"Transaction stored: {data['name']} [{data['transaction_id']}]")

    @contextmanager
    def transaction(self, name: str, transaction_type: str = 'request'):
        """Context manager for transactions."""
        txn = self.begin_transaction(name, transaction_type)
        try:
            yield txn
            self.end_transaction('success', 'success')
        except Exception as e:
            self.capture_exception(e)
            self.end_transaction('error', 'failure')
            raise

    @contextmanager
    def span(self, name: str, span_type: str = 'custom'):
        """Context manager for spans within the current transaction."""
        if not self._current_transaction:
            yield None
            return

        span = self._current_transaction.create_span(name, span_type)
        span.start()
        try:
            yield span
            span.end('success')
        except Exception as e:
            import traceback
            span.stack_trace = traceback.format_exc()
            span.end('failure')
            raise

    def capture_exception(self, exception: Exception):
        """Capture an exception with sanitized stack trace."""
        import traceback

        raw_trace = traceback.format_exc()
        sanitized_trace = self._sanitizer.sanitize_stack_trace(raw_trace)

        error_data = {
            'error_id': hashlib.md5(
                f"{type(exception).__name__}{time.time_ns()}".encode()
            ).hexdigest()[:16],
            'timestamp': time.time(),
            'exception': {
                'type': type(exception).__name__,
                'message': self._sanitizer.sanitize_string(str(exception)),
                'stacktrace': sanitized_trace,
            },
            'transaction_id': (
                self._current_transaction.transaction_id
                if self._current_transaction else None
            ),
        }

        if len(self._errors) >= self.config['max_errors_buffer']:
            self._flush_errors()

        self._errors.append(error_data)
        logger.error(
            f"Exception captured: {error_data['exception']['type']} "
            f"[{error_data['error_id']}]"
        )

    def capture_sql_query(
        self,
        query: str,
        params: Optional[tuple] = None,
        duration_ms: Optional[float] = None,
        database: str = 'unknown',
    ):
        """Capture a SQL query with sanitization."""
        if not self._current_transaction:
            return

        sanitized_query = self._sanitizer.sanitize_sql(query)

        span = self._current_transaction.create_span(
            f"SQL: {sanitized_query[:50]}...",
            'db.sql'
        )
        span.start()
        span.set_context({
            'db': {
                'type': 'sql',
                'instance': database,
                'statement': sanitized_query,
                # Never include raw params - they may contain sensitive data
                'params': '[SANITIZED]' if params else None,
            }
        })
        if duration_ms is not None:
            span.duration_ms = duration_ms
        span.end('success')

    def capture_request(
        self,
        method: str,
        url: str,
        headers: Optional[Dict[str, str]] = None,
        body: Optional[Any] = None,
        status_code: Optional[int] = None,
        response_headers: Optional[Dict[str, str]] = None,
        response_body: Optional[Any] = None,
    ):
        """Capture HTTP request/response data with sanitization."""
        if not self._current_transaction:
            return

        sanitized_url = self._sanitizer.sanitize_url(url)
        sanitized_headers = (
            self._sanitizer.sanitize_headers(headers) if headers else {}
        )
        sanitized_response_headers = (
            self._sanitizer.sanitize_headers(response_headers)
            if response_headers else {}
        )

        # Sanitize request body
        sanitized_body = None
        if body and self.config['capture_body'] in ('all', 'transactions'):
            if isinstance(body, dict):
                sanitized_body = self._sanitizer.sanitize_dict(body)
            elif isinstance(body, str):
                sanitized_body = self._sanitizer.sanitize_string(body)

        # Sanitize response body
        sanitized_response_body = None
        if response_body and self.config['capture_body'] in ('all', 'transactions'):
            if isinstance(response_body, dict):
                sanitized_response_body = self._sanitizer.sanitize_dict(response_body)
            elif isinstance(response_body, str):
                sanitized_response_body = self._sanitizer.sanitize_string(
                    response_body
                )

        context = {
            'request': {
                'method': method,
                'url': sanitized_url,
                'headers': sanitized_headers,
                'body': sanitized_body,
            },
            'response': {
                'status_code': status_code,
                'headers': sanitized_response_headers,
                'body': sanitized_response_body,
            },
        }

        self._current_transaction.set_context(context)

    def _flush_transactions(self):
        """Flush buffered transactions to the APM server."""
        if not self._transactions:
            return

        # In production, this would send to the APM server
        # Here we log the count and clear the buffer
        count = len(self._transactions)
        logger.info(f"Flushing {count} transactions to APM server")

        # Simulate sending - in production use secure HTTPS transport
        self._send_to_server({
            'transactions': self._transactions,
            'service': {
                'name': self.config['service_name'],
                'environment': self.config['environment'],
            }
        })
        self._transactions.clear()

    def _flush_errors(self):
        """Flush buffered errors to the APM server."""
        if not self._errors:
            return

        count = len(self._errors)
        logger.info(f"Flushing {count} errors to APM server")

        self._send_to_server({
            'errors': self._errors,
            'service': {
                'name': self.config['service_name'],
                'environment': self.config['environment'],
            }
        })
        self._errors.clear()

    def _send_to_server(self, payload: Dict[str, Any]):
        """
        Send data to APM server.
        In production, this would use HTTPS with proper authentication.
        """
        # Final sanitization before sending
        sanitized_payload = self._sanitizer.sanitize_dict(payload)

        # Log sanitized summary (never log full payload in production)
        if 'transactions' in sanitized_payload:
            for txn in sanitized_payload['transactions']:
                logger.info(
                    f"  -> Transaction: {txn.get('name')} "
                    f"duration={txn.get('duration_ms')}ms "
                    f"outcome={txn.get('outcome')} "
                    f"spans={txn.get('span_count', 0)}"
                )

        # In production: send via HTTPS to APM server
        # import requests
        # headers = {'Authorization': f'Bearer {self.config["secret_token"]}'}
        # requests.post(
        #     f"{self.config['server_url']}/intake/v2/events",
        #     json=sanitized_payload,
        #     headers=headers,
        #     verify=self.config['verify_server_cert'],
        #     timeout=self.config['server_timeout'],
        # )

    def flush(self):
        """Flush all buffered data."""
        self._flush_transactions()
        self._flush_errors()

    def get_stats(self) -> Dict[str, Any]:
        """Get APM client statistics (sanitized)."""
        return {
            'service_name': self.config['service_name'],
            'environment': self.config['environment'],
            'buffered_transactions': len(self._transactions),
            'buffered_errors': len(self._errors),
            'is_recording': self._is_recording,
            # Never expose server_url or secret_token in stats
        }


