def trace_function(apm_client: APMClient, span_type: str = 'custom'):
    """Decorator to trace function execution as a span."""
    def decorator(func: Callable):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Sanitize function arguments before including in span
            sanitized_kwargs = APMDataSanitizer.sanitize_dict(
                {k: str(v) for k, v in kwargs.items()}
            )

            with apm_client.span(func.__name__, span_type) as span:
                if span:
                    span.set_context({
                        'function': func.__name__,
                        'module': func.__module__,
                        'args_count': len(args),
                        'kwargs': sanitized_kwargs,
                    })
                result = func(*args, **kwargs)
                return result
        return wrapper
    return decorator


def trace_transaction(
    apm_client: APMClient, transaction_type: str = 'request'
):
    """Decorator to trace function execution as a transaction."""
    def decorator(func: Callable):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            with apm_client.transaction(
                func.__name__, transaction_type
            ) as txn:
                result = func(*args, **kwargs)
                return result
        return wrapper
    return decorator


