class DatabaseQueryTracker:
    """Tracks database queries with APM integration and sanitization."""

    def __init__(self, apm_client: APMClient, database_name: str = 'main'):
        self.apm_client = apm_client
        self.database_name = database_name

    @contextmanager
    def track_query(self, query: str, params: Optional[tuple] = None):
        """Context manager to track a database query."""
        start_time = time.monotonic()
        try:
            yield
        finally:
            duration_ms = (time.monotonic() - start_time) * 1000
            self.apm_client.capture_sql_query(
                query=query,
                params=params,
                duration_ms=duration_ms,
                database=self.database_name,
            )

    def execute(self, query: str, params: Optional[tuple] = None):
        """Simulate executing a query with tracking."""
        with self.track_query(query, params):
            # In production, this would execute the actual query
            time.sleep(0.01)  # Simulate query execution
            logger.info(
                f"Query executed: {APMDataSanitizer.sanitize_sql(query)[:80]}..."
            )


# ============================================================================
# HTTP Request Tracker
# ============================================================================

class HTTPRequestTracker:
    """Tracks HTTP requests with APM integration and sanitization."""

    def __init__(self, apm_client: APMClient):
        self.apm_client = apm_client

    def track_request(
        self,
        method: str,
        url: str,
        headers: Optional[Dict[str, str]] = None,
        body: Optional[Any] = None,
        status_code: int = 200,
        response_headers: Optional[Dict[str, str]] = None,
        response_body: Optional[Any] = None,
    ):
        """Track an HTTP request/response."""
        self.apm_client.capture_request(
            method=method,
            url=url,
            headers=headers,
            body=body,
            status_code=status_code,
            response_headers=response_headers,
            response_body=response_body,
        )


# ============================================================================
# Example Application demonstrating APM usage
# ============================================================================

class SampleApplication:
    """Sample application demonstrating APM instrumentation."""

    def __init__(self):
        self.apm = APMClient({
            'service_name': 'sample-web-app',
            'environment': 'development',
            'capture_body': 'all',
        })
        self.db = DatabaseQueryTracker(self.apm, 'users_db')
        self.http_tracker = HTTPRequestTracker(self.apm)

    def handle_user_login(self, username: str, password: str):
        """Simulate handling a user login request."""
        with self.apm.transaction('POST /api/login', 'request') as txn:
            # Track the incoming request
            self.http_tracker.track_request(
                method='POST',
                url='https://api.example.com/api/login',
                headers={
                    'Content-Type': 'application/json',
                    'Authorization': 'Bearer eyJhbGciOiJIUzI1NiJ9.secret.token',
                    'X-Request-ID': 'req-12345',
                },
                body={
                    'username': username,
                    'password': password,  # This should be sanitized!
                    'remember_me': True,
                },
            )

            # Track database query
            with self.apm.span('authenticate_user', 'db'):
                self.db.execute(
                    "SELECT id, username, email FROM users WHERE username = %s AND password_hash = %s",
                    (username, 'hashed_password_value'),
                )

            # Track token generation
            with self.apm.span('generate_token', 'custom') as span:
                time.sleep(0.005)  # Simulate work
                if span:
                    span.set_label('token_type', 'jwt')
                    # This should be blocked:
                    span.set_label('secret_key', 'my-secret-key-123')

            txn.set_label('user', username)
            txn.set_custom_context({
                'user_id': 12345,
                'login_method': 'password',
                'api_key': 'should-be-redacted',
            })

            # Track response
            self.http_tracker.track_request(
                method='POST',
                url='https://api.example.com/api/login',
                status_code=200,
                response_headers={
                    'Content-Type': 'application/json',
                    'Set-Cookie': 'session=abc123; HttpOnly; Secure',
                },
                response_body={
                    'success': True,
                    'token': 'eyJhbGciOiJIUzI1NiJ9.payload.signature',
                    'user_id': 12345,
                },
            )

    def handle_user_profile(self, user_id: int):
        """Simulate handling a user profile request."""
        with self.apm.transaction('GET /api/users/{id}', 'request') as txn:
            self.http_tracker.track_request(
                method='GET',
                url=f'https://api.example.com/api/users/{user_id}?api_key=secret123&format=json',
                headers={
                    'Accept': 'application/json',
                    'Authorization': 'Bearer some-token',
                },
            )

            with self.apm.span('fetch_user_profile', 'db'):
                self.db.execute(
                    "SELECT id, username, email, ssn, credit_card FROM users WHERE id = %s",
                    (user_id,),
                )

            with self.apm.span('fetch_user_orders', 'db'):
                self.db.execute(
                    "SELECT o.id, o.total, o.status FROM orders o WHERE o.user_id = %s ORDER BY o.created_at DESC LIMIT 10",
                    (user_id,),
                )

            txn.set_label('user_id', str(user_id))

    def handle_payment(self, user_id: int, amount: float, card_number: str):
        """Simulate handling a payment - demonstrates sensitive data handling."""
        with self.apm.transaction('POST /api/payments', 'request') as txn:
            self.http_tracker.track_request(
                method='POST',
                url='https://api.example.com/api/payments',
                headers={
                    'Content-Type': 'application/json',
                    'Authorization': 'Bearer payment-token-xyz',
                },
                body={
                    'user_id': user_id,
                    'amount': amount,
                    'currency': 'USD',
                    'card_number': card_number,
                    'cvv': '123',
                    'billing_address': '123 Main St',
                },
            )

            with self.apm.span('process_payment', 'external'):
                time.sleep(0.02)  # Simulate payment processing

            with self.apm.span('record_payment', 'db'):
                self.db.execute(
                    "INSERT INTO payments (user_id, amount, card_last_four, status) VALUES (%s, %s, %s, 'completed')",
                    (user_id, amount, card_number[-4:]),
                )

            txn.set_label('payment_amount', str(amount))
            txn.set_label('currency', 'USD')

    def handle_error_scenario(self):
        """Simulate an error scenario."""
        with self.apm.transaction('GET /api/error', 'request') as txn:
            try:
                with self.apm.span('risky_operation', 'custom'):
                    # Simulate an error with sensitive data in the message
                    raise ValueError(
                        "Database connection failed for user password=secret123 "
                        "with token=eyJhbGciOiJIUzI1NiJ9.test.sig"
                    )
            except ValueError:
                pass  # Exception is captured by the transaction context manager
                # Re-capture manually to demonstrate
                try:
                    raise ValueError("Sample error for demonstration")
                except ValueError as e:
                    self.apm.capture_exception(e)

    def run_demo(self):
        """Run the demo application."""
        logger.info("=" * 60)
        logger.info("Starting APM Demo Application")
        logger.info("=" * 60)

        # Scenario 1: User Login
        logger.info("\n--- Scenario 1: User Login ---")
        self.handle_user_login('john_doe', 'super_secret_password123')

        # Scenario 2: User Profile
        logger.info("\n--- Scenario 2: User Profile ---")
        self.handle_user_profile(12345)

        # Scenario 3: Payment Processing
        logger.info("\n--- Scenario 3: Payment Processing ---")
        self.handle_payment(12345, 99.99, '4111-1111-1111-1111')

        # Scenario 4: Error Handling
        logger.info("\n--- Scenario 4: Error Handling ---")
        self.handle_error_scenario()

        # Flush all data
        self.apm.flush()

        # Print stats
        logger.info("\n--- APM Stats ---")
        stats = self.apm.get_stats()
        for key, value in stats.items():
            logger.info(f"  {key}: {value}")

        # Demonstrate sanitization directly
        logger.info("\n--- Sanitization Examples ---")
        self._demonstrate_sanitization()

    def _demonstrate_sanitization(self):
        """Show sanitization in action."""
        # Test header sanitization
        headers = {
            'Content-Type': 'application/json',
            'Authorization': 'Bearer my-secret-token',
            'X-Request-ID': 'req-12345',
            'Cookie': 'session=abc123',
            'X-Custom-Header': 'safe-value',
        }
        sanitized = APMDataSanitizer.sanitize_headers(headers)
        logger.info(f"  Sanitized headers: {sanitized}")

        # Test URL sanitization
        url = 'https://api.example.com/users?api_key=secret123&format=json&token=abc'
        sanitized_url = APMDataSanitizer.sanitize_url(url)
        logger.info(f"  Sanitized URL: {sanitized_url}")

        # Test SQL sanitization
        sql = "SELECT * FROM users WHERE password = 'secret123' AND username = 'john'"
        sanitized_sql = APMDataSanitizer.sanitize_sql(sql)
        logger.info(f"  Sanitized SQL: {sanitized_sql}")

        # Test dict sanitization
        data = {
            'username': 'john',
            'password': 'secret123',
            'api_key': 'key-12345',
            'preferences': {
                'theme': 'dark',
                'secret_answer': 'my pet name',
            },
            'credit_card_number': '4111-1111-1111-1111',
        }
        sanitized_data = APMDataSanitizer.sanitize_dict(data)
        logger.info(f"  Sanitized dict: {sanitized_data}")

        # Test value pattern detection
        test_values = [
            'Normal text',
            '4111-1111-1111-1111',
            '123-45-6789',
            'user@example.com',
            'Bearer eyJhbGciOiJIUzI1NiJ9.test.signature',
            'AKIAIOSFODNN7EXAMPLE',
        ]
        for val in test_values:
            is_sensitive = APMDataSanitizer.contains_sensitive_value(val)
            logger.info(
                f"  Value '{val[:30]}...' sensitive: {is_sensitive}"
            )


